package genxsolution.vms.vmsbackend.employee_hr_management.employee_advance.service;
import genxsolution.vms.vmsbackend.employee_hr_management.employee_advance.dto.*; import genxsolution.vms.vmsbackend.employee_hr_management.employee_advance.mapper.EmployeeAdvanceMapper; import genxsolution.vms.vmsbackend.employee_hr_management.employee_advance.repository.EmployeeAdvanceRepository; import genxsolution.vms.vmsbackend.employee_hr_management.exception.HrResourceNotFoundException; import org.springframework.stereotype.Service; import java.util.*;
@Service public class EmployeeAdvanceService { private final EmployeeAdvanceRepository repository; private final EmployeeAdvanceMapper mapper; public EmployeeAdvanceService(EmployeeAdvanceRepository repository,EmployeeAdvanceMapper mapper){this.repository=repository;this.mapper=mapper;} public List<EmployeeAdvanceResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public EmployeeAdvanceResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new HrResourceNotFoundException("EmployeeAdvance", id.toString())); } public EmployeeAdvanceResponse create(EmployeeAdvanceUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public EmployeeAdvanceResponse update(UUID id,EmployeeAdvanceUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new HrResourceNotFoundException("EmployeeAdvance", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new HrResourceNotFoundException("EmployeeAdvance", id.toString()); } }
